import React from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useTheme } from '../../context/ThemeContext';
import { FiGrid, FiUsers, FiCalendar, FiClock, FiUserCheck, FiTrendingUp, FiBookmark, FiShield, FiMessageSquare, FiLogOut, FiBriefcase, FiMenu, FiSun, FiMoon } from 'react-icons/fi';
import { HiOutlineIdentification } from 'react-icons/hi';

const navItems = [
  { section: 'Main' },
  { path: '/', label: 'Dashboard', icon: FiGrid, end: true },
  { section: 'Employee Management' },
  { path: '/admin/users', label: 'Admin - Users', icon: FiShield },
  { path: '/admin/job-titles', label: 'Admin - Job Titles', icon: FiBriefcase },
  { path: '/admin/pay-grades', label: 'Admin - Pay Grades', icon: FiTrendingUp },
  { path: '/admin/work-shifts', label: 'Admin - Work Shifts', icon: FiClock },
  { path: '/admin/organization', label: 'Admin - Organization', icon: FiBookmark },
  { path: '/pim', label: 'PIM - Employees', icon: HiOutlineIdentification },
  { path: '/pim/add', label: 'PIM - Add Employee', icon: FiUsers },
  { section: 'Leave & Time' },
  { path: '/leave/requests', label: 'Leave - Requests', icon: FiCalendar },
  { path: '/leave/types', label: 'Leave - Types', icon: FiCalendar },
  { path: '/leave/entitlements', label: 'Leave - Entitlements', icon: FiCalendar },
  { path: '/leave/holidays', label: 'Leave - Holidays', icon: FiCalendar },
  { path: '/time/timesheets', label: 'Time - Timesheets', icon: FiClock },
  { path: '/time/attendance', label: 'Time - Attendance', icon: FiClock },
  { section: 'Recruitment' },
  { path: '/recruitment/vacancies', label: 'Recruitment - Vacancies', icon: FiUserCheck },
  { path: '/recruitment/candidates', label: 'Recruitment - Candidates', icon: FiUsers },
  { section: 'Performance & Directory' },
  { path: '/performance/reviews', label: 'Performance Reviews', icon: FiTrendingUp },
  { path: '/directory', label: 'Directory', icon: FiBookmark },
  { section: 'Other' },
  { path: '/maintenance', label: 'Maintenance', icon: FiShield },
  { path: '/buzz', label: 'Buzz', icon: FiMessageSquare },
];

const Layout = () => {
  const { user, logout } = useAuth();
  const { theme, toggleTheme } = useTheme();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  const empName = user?.employeeId?.fullName || user?.username || 'User';
  const initials = empName.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);

  return (
    <div className="layout">
      <aside className="sidebar">
        <div className="sidebar-logo">
          <span>Orange</span>HRM
        </div>
        <nav className="sidebar-nav">
          {navItems.map((item, i) => {
            if (item.section) {
              return <div key={i} className="nav-section">{item.section}</div>;
            }
            const Icon = item.icon;
            return (
              <NavLink
                key={item.path}
                to={item.path}
                end={item.end}
                className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`}
              >
                <Icon /><span>{item.label}</span>
              </NavLink>
            );
          })}
        </nav>
      </aside>
      <div className="main-content">
        <header className="header">
          <div className="header-left">
            <h3>OrangeHRM Clone</h3>
          </div>
          <div className="header-right">
            <button className="theme-toggle" onClick={toggleTheme} title={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}>
            {theme === 'light' ? <FiMoon /> : <FiSun />}
          </button>
          <div className="header-user">
              <div className="header-avatar">{initials}</div>
              <span>{empName} ({user?.role})</span>
            </div>
            <button className="btn btn-sm btn-outline" onClick={handleLogout}>
              <FiLogOut /> Logout
            </button>
          </div>
        </header>
        <div className="page-content">
          <Outlet />
        </div>
      </div>
    </div>
  );
};

export default Layout;
